"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import {
  Calendar,
  Users,
  Stethoscope,
  Pill,
  Activity,
  AlertCircle,
  Sparkles,
  X,
  Phone,
  ChevronRight,
  FileText,
  Trash2,
  ChevronLeft,
  Menu,
} from "lucide-react";

/* -------------------- TYPES -------------------- */

type Appointment = {
  id: string;
  date: string;
  time: string;
  title: string;
};

type UserData = {
  personalInfo: {
    emergencyContacts: { name: string; phone: string; relation: string }[];
  };
  currentMedical: {
    doctors: { name: string; phone: string; speciality: string }[];
    medications: { name: string; dosage: string; frequency: string }[];
    conditions: string[];
  };
};

type Props = {
  userData?: UserData;
  appointments?: Appointment[];
  onAddAppointment: (a: Appointment) => void;
  onDeleteAppointment: (id: string) => void;
  onUpdateEmergencyContacts: (c: any[]) => void;
};

/* -------------------- HELPERS -------------------- */

const formatDateKey = (d: Date) =>
  `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, "0")}-${String(
    d.getDate()
  ).padStart(2, "0")}`;

/* -------------------- PAGE -------------------- */

export default function HomePage({
  userData,
  appointments = [],
  onAddAppointment,
  onDeleteAppointment,
  onUpdateEmergencyContacts,
}: Props) {
  const router = useRouter();


  /* ---------- SAFE DATA (CRITICAL FIX) ---------- */
  const safeUserData: UserData = userData ?? {
    personalInfo: { emergencyContacts: [] },
    currentMedical: {
      doctors: [],
      medications: [],
      conditions: [],
    },
  };

  const { emergencyContacts } = safeUserData.personalInfo;
  const { doctors, medications, conditions } = safeUserData.currentMedical;

  /* ---------------- STATE ---------------- */
  const [activeModal, setActiveModal] = useState<string | null>(null);
  const [showSummaryModal, setShowSummaryModal] = useState(false);
  const [summaryText, setSummaryText] = useState("");
  const [recentDocs, setRecentDocs] = useState<any[]>([]);
  const [isMenuOpen, setIsMenuOpen] = useState(false);

  /* ---------------- LOGIC ---------------- */

  const handleGetSummary = () => {
    setRecentDocs([
      { id: "1", name: "Blood Test.pdf" },
      { id: "2", name: "X-Ray.pdf" },
    ]);

    setSummaryText(
      `📋 AI MEDICAL SUMMARY\n\n• No critical allergies\n• Medications stable\n• Follow-up recommended in 3 months`
    );
    setShowSummaryModal(true);
  };

  const cards = [
    { id: "appointments", title: "Appointments", icon: Calendar },
    { id: "emergency", title: "Emergency Contacts", icon: Users },
    { id: "doctors", title: "Medical Team", icon: Stethoscope },
    { id: "medications", title: "Medications", icon: Pill },
  ];

  const renderModal = () => {
    switch (activeModal) {
      case "appointments":
        return (
          <CalendarView
            appointments={appointments}
            onAddAppointment={onAddAppointment}
            onDeleteAppointment={onDeleteAppointment}
          />
        );
      case "emergency":
        return (
          <EmergencyView
            data={emergencyContacts}
            onDelete={(i: number) =>
              onUpdateEmergencyContacts(
                emergencyContacts.filter((_, idx) => idx !== i)
              )
            }
          />
        );
      case "doctors":
        return <DoctorsView data={doctors} />;
      case "medications":
        return <MedsView data={medications} />;
      default:
        return null;
    }
  };

  /* ---------------- UI ---------------- */

  return (
    <div className="min-h-screen bg-gradient-to-b from-[#003B46] via-[#006770] to-[#00A3A9] text-white">
      {/* HEADER */}
      <header className="sticky top-0 z-40 bg-[#006770]/90 backdrop-blur border-b border-white/20">
        <div className="max-w-7xl mx-auto px-4 py-3 flex justify-between items-center">
          <h1 className="font-bold text-xl">Vytara</h1>

          <div className="flex gap-3">
            <button
              onClick={handleGetSummary}
              className="flex items-center gap-2 bg-purple-600 px-4 py-2 rounded-lg font-semibold hover:bg-purple-700"
            >
              <Sparkles size={16} /> Get Summary
            </button>

            <button
              onClick={() => setIsMenuOpen(!isMenuOpen)}
              className="p-2 rounded-lg hover:bg-white/20"
            >
              {isMenuOpen ? <X /> : <Menu />}
            </button>

            {isMenuOpen && (
              <div className="absolute right-4 top-16 bg-white text-gray-800 rounded-xl shadow-xl overflow-hidden">
                <button
                  onClick={() => {
                    router.push("/vault");
                    setIsMenuOpen(false);
                  }}

                  className="block px-4 py-3 hover:bg-teal-50 w-full text-left"
                >
                  Vault
                </button>
                <button
                  onClick={() => {
                    router.push("/profile");
                    setIsMenuOpen(false);
                  }}

                  className="block px-4 py-3 hover:bg-teal-50 w-full text-left"
                >
                  Profile
                </button>
              </div>
            )}
          </div>
        </div>
      </header>

      {/* SOS */}
      <div className="flex justify-center my-10">
        <button className="w-36 h-36 rounded-full bg-red-600 flex flex-col items-center justify-center shadow-2xl hover:scale-105 transition">
          <AlertCircle size={42} />
          <span className="font-bold text-2xl mt-1">SOS</span>
        </button>
      </div>

      {/* CARDS */}
      <div className="max-w-7xl mx-auto px-4 grid grid-cols-2 md:grid-cols-4 gap-6">
        {cards.map((c) => {
          const Icon = c.icon;
          return (
            <div
              key={c.id}
              onClick={() => setActiveModal(c.id)}
              className="bg-white text-gray-800 rounded-3xl p-6 text-center shadow-xl hover:scale-105 cursor-pointer transition"
            >
              <div className="w-14 h-14 mx-auto mb-3 bg-teal-100 rounded-full flex items-center justify-center">
                <Icon className="text-teal-600" />
              </div>
              <h3 className="font-bold">{c.title}</h3>
            </div>
          );
        })}
      </div>

      {/* MODALS */}
      {activeModal && (
        <Modal onClose={() => setActiveModal(null)}>
          {renderModal()}
        </Modal>
      )}

      {showSummaryModal && (
        <Modal onClose={() => setShowSummaryModal(false)}>
          <h2 className="text-xl font-bold mb-4">AI Medical Summary</h2>
          <pre className="whitespace-pre-wrap text-gray-700">
            {summaryText}
          </pre>
        </Modal>
      )}
    </div>
  );
}

/* -------------------- SHARED MODAL -------------------- */

function Modal({ children, onClose }: any) {
  return (
    <div
      className="fixed inset-0 bg-black/60 flex items-center justify-center p-4 z-50"
      onClick={onClose}
    >
      <div
        onClick={(e) => e.stopPropagation()}
        className="bg-white rounded-3xl p-6 max-w-3xl w-full text-gray-800 relative"
      >
        <button
          onClick={onClose}
          className="absolute top-4 right-4 p-2 bg-gray-100 rounded-full"
        >
          <X />
        </button>
        {children}
      </div>
    </div>
  );
}

/* -------------------- VIEWS -------------------- */

function CalendarView({ appointments, onAddAppointment, onDeleteAppointment }: any) {
  return (
    <AppointmentsModal
      appointments={appointments}
      onClose={() => {}}
      onAddAppointment={onAddAppointment}
      onDeleteAppointment={onDeleteAppointment}
    />
  );
}

function EmergencyView({ data, onDelete }: any) {
  return data.length === 0 ? (
    <p>No emergency contacts</p>
  ) : (
    data.map((c: any, i: number) => (
      <div key={i} className="flex justify-between mb-3">
        <div>
          <p className="font-bold">{c.name}</p>
          <p className="text-sm">{c.relation} • {c.phone}</p>
        </div>
        <button onClick={() => onDelete(i)}>
          <Trash2 className="text-red-500" />
        </button>
      </div>
    ))
  );
}

function DoctorsView({ data }: any) {
  return data.length === 0 ? <p>No doctors</p> : data.map((d: any, i: number) => (
    <p key={i} className="mb-2">{d.name} – {d.speciality}</p>
  ));
}

function MedsView({ data }: any) {
  return data.length === 0 ? <p>No medications</p> : data.map((m: any, i: number) => (
    <p key={i} className="mb-2">{m.name} – {m.dosage}</p>
  ));
}
